mapper.select:
SELECT id, conversation_id, user_id, last_read_message_id, last_read_at
FROM message_reads
WHERE conversation_id = #{conversationId} AND user_id = #{userId}

SELECT c.id as conversation_id, COUNT(m.id) as unread_count FROM conversations c LEFT JOIN message_reads mr ON mr.conversation_id = c.id AND mr.user_id = #{userId} LEFT JOIN messages m ON m.conversation_id = c.id AND m.sender_id != #{userId} AND m.status = 1 AND m.id > COALESCE(mr.last_read_message_id, 0) WHERE c.id IN
#{convId}
GROUP BY c.id
